1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - nextGeneration", () => {
6	  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
10	    expect(
11	      nextGeneration([
12	        [0, 1],
13	        [1, 1],
14	      ]),
15	    ).toEqual([]);
16	  });
17	  it("should keep a live cell with 3 live neighbors alive (survival)", () => {
18	    const result = nextGeneration([
19	      [0, 0],
20	      [1, 0],
21	      [2, 0],
22	      [1, 1],
23	    ]);
24	    expect(result.sort()).toEqual([
25	      [1, 0],
26	      [1, 1],
27	    ]);
28	  });
29	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
30	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
31	  it.todo("should keep a block still life unchanged");
32	  it.todo("should oscillate a vertical blinker to a horizontal blinker (negative coordinates)");
33	});
34

1	export type Cell = [number, number];
2	
3	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
4	  liveCells.filter(([x, y]) => {
5	    const liveNeighbors = liveCells.filter(
6	      ([nx, ny]) =>
7	        Math.abs(nx - x) <= 1 &&
8	        Math.abs(ny - y) <= 1 &&
9	        !(nx === x && ny === y),
10	    ).length;
11	    return liveNeighbors === 3;
12	  });
