it("should keep a live cell with 3 live neighbors alive (survival)", () => {
  const result = nextGeneration([
    [0, 0],
    [1, 0],
    [2, 0],
    [1, 1],
  ]);
  expect(result.sort()).toEqual([
    [1, 0],
    [1, 1],
  ]);
});

